import {
  rectangle, rounded_rectangle, polygon, circle, segment,
  union, dilate, render,
} from '../../src/index.js';

// Bare-bones control tower at a small regional airport — single building,
// side view, minimal embellishment. Scene-completion should add parked
// planes / ground vehicles / runway lights / terminal etc.

// Tower base (cylinder approximated as rounded_rectangle)
const towerBase = rounded_rectangle([0.12, 0.50], 0.02, [-0.05, 0.05]);

// Tower cabin (the glass cap at top)
const towerCabin = rounded_rectangle([0.22, 0.10], 0.03, [-0.05, 0.40]);

// Antenna mast
const mast = segment([-0.05, 0.45], [-0.05, 0.62], 0.004);
const antennaTip = circle(0.012, [-0.05, 0.63]);

// Terminal building (small wide block to one side)
const terminal = rectangle([0.50, 0.16], [0.30, -0.08]);
const terminalRoof = polygon([
  [ 0.05, 0.00],
  [ 0.55, 0.00],
  [ 0.50, 0.05],
  [ 0.10, 0.05],
]);

// Ground strip
const ground = rectangle([1.6, 0.10], [0, -0.36]);
const sky    = rectangle([1.6, 0.80], [0,  0.20]);

const layers = [
  { sdf: sky,    color: [150, 180, 210] },
  { sdf: ground, color: [80,  85,  72]  },
  { sdf: dilate(towerBase, 0.012),  color: [20, 25, 35] },
  { sdf: towerBase,                 color: [230, 225, 215] },
  { sdf: dilate(towerCabin, 0.012), color: [20, 25, 35] },
  { sdf: towerCabin,                color: [60, 90, 130] },
  { sdf: mast,                      color: [20, 25, 35] },
  { sdf: antennaTip,                color: [200, 40, 40] },
  { sdf: dilate(terminal, 0.010),   color: [20, 25, 35] },
  { sdf: terminal,                  color: [220, 215, 200] },
  { sdf: terminalRoof,              color: [110, 90, 70] },
];
const canvas = document.getElementById('c');
const ctx = canvas.getContext('2d');
render.silhouette(ctx, layers, {
  view: 1.4,
  background: { top: [130, 165, 195], bottom: [195, 215, 230] },
});
```

**Composition notes**: Bare regional airport — control tower + small terminal building. NO planes on apron, NO ground vehicles, NO runway, NO distant traffic. The 3D lift should INFER: parked aircraft along the apron (array), ground service vehicles (scatter), runway with edge lights (array of lamps), maybe distant taxiing plane. Scene completion territory.
